// ShaderLab Custom — Sphere
uniform float uTime,uScale,uLevel,uPmScale,uSpeed,uAmp,uSize;
uniform float uLodFade;
attribute float aPhase;
varying float vBlink;
varying float vPhase;
void main(){
  vBlink=0.0;
  vPhase=aPhase;
  vec3 wpos=position*uPmScale;
  vec4 mvP=modelViewMatrix*vec4(wpos,1.0);
  gl_PointSize=0.0;
  gl_PointSize=uScale*0.33*(1.1+vBlink*0.0)*60.7/-mvP.z;
  {float _v=sin(uTime*0.7+vPhase*6.2832)*0.387;float _base=gl_PointSize>0.0?gl_PointSize:0.31*uScale*350.0/-mvP.z;gl_PointSize=_base*(1.0+_v);}
  if(gl_PointSize<=0.0)
    gl_PointSize=uScale*uSize*(1.0+vBlink*uAmp*3.0)/-mvP.z;
  gl_PointSize*=uLodFade;
  gl_Position=projectionMatrix*mvP;
}

